window.LEARNPROJECTS = [{"schemaVersion":"1.0","slug":"rex-fabrique","title":"REX — Fabrique de génération de veille","goal":"Retour d'expérience d'ingénierie : ce qu'on a testé pour fiabiliser la génération de synthèses de veille sourcées, pourquoi, et les résultats.","summary":"Journal des expériences d'ingénierie derrière la fabrique TechWatch : chaque entrée dit **ce qu'on a testé**, **pourquoi**, et **le résultat** (validé, abandonné, ou en cours). Le fil rouge : rendre la génération fiable, sourcée et vérifiable — y compris avec des modèles bon marché — sans jamais publier un pack qui ne tient pas ses sources. Alimenté au fur et à mesure de l'avancement.","tags":["rex","llm","pipeline","eval","cout-qualite"],"status":"actif","experiments":[{"title":"Décomposer le monolithe en pipeline reprenable","status":"validé","date":"2026-07-05","tested":"Remplacer un unique appel `claude -p` monolithique par un pipeline en étapes ordonnées (sources → draft → claims → fidélité → quiz → juge → assemble), checkpointé et reprenable après crash.","why":"Un monolithe est opaque, non reprenable, et impossible à gater étape par étape ou à router vers plusieurs modèles.","result":"Pipeline reprenable en production (checkpoints atomiques + lock, boucle de réparation fidélité, gate par étape). C'est la fondation sur laquelle tout le reste s'appuie.","packs":["workflow-deterministe-vs-agents"]},{"title":"Gate schéma fail-closed en tête d'assemble","status":"validé","date":"2026-07-06","tested":"Extraire la validation du pack en cœur pur, puis la poser comme gate BLOQUANT au début de l'assemblage : un pack schéma-invalide devient `abandoned{pack-invalide}`, jamais écrit.","why":"Un modèle bon marché bâcle facilement le squelette ; sans gate, un pack malformé passait en silence dans la bibliothèque.","result":"Invariant tenu : aucun pack malformé n'est publiable. Le système échoue proprement plutôt que de salir la bibliothèque.","packs":["guardrails","eval-driven-development"]},{"title":"Un modèle par rôle + provenance véridique (ADR 0008)","status":"validé","date":"2026-07-07","tested":"Injecter un modèle distinct par rôle (générateur / juge d'entailment / juge holistique) via des ports ; une provenance qui ne ment pas sur le tier utilisé ; une clé de cache des étapes de jugement dépendante du tier du juge.","why":"Débloquer « générateur bon marché + juge fort » sans jamais dégrader le jugement de fidélité en partageant un modèle faible.","result":"Les tiers s'appliquent bien par rôle et `provenance.generator`/`.judge.model` sont véridiques. Prérequis indispensable au générateur bon marché.","packs":["choix-gestion-modeles","provenance-versionnement-contenu"]},{"title":"Modèle bon marché comme auteur unique (Haiku composite)","status":"abandonné","date":"2026-07-07","tested":"Faire produire à Haiku le draft éditorial ET les claims en un seul appel composite, pour réduire le coût sur tout le volume.","why":"Hypothèse : un modèle rapide et bon marché suffit comme auteur unique si on soigne le prompt.","result":"Haiku bâcle le squelette → 76 erreurs de schéma → le gate abandonne. Conclusion nette : pas viable comme auteur unique du draft. C'est ce qui a motivé le chantier de scission.","packs":["choix-gestion-modeles","finops-ia-couts"]},{"title":"Scinder draft / claims, un modèle par étape","status":"validé","date":"2026-07-08","tested":"Séparer la synthèse éditoriale (`draft`, tier fort) de l'extraction quote-first (`claims`, tier bon marché) ; l'assemblage lit le squelette depuis le checkpoint `draft` ; provenance composite véridique du split.","why":"Qu'un tier fort produise le petit squelette fiable pendant qu'un tier bon marché absorbe le volume (claims + quiz).","result":"5 commits, 220/220 tests verts, revue finale = « merge OK ». Le draft (sonnet) passe désormais le gate schéma : le blocage des « 76 erreurs » disparaît. Le draft n'est plus le point de rupture.","packs":["workflow-deterministe-vs-agents","choix-gestion-modeles"]},{"title":"Dogfood cheap-gen : le goulot se déplace","status":"en-cours","date":"2026-07-08","tested":"Dogfood en conditions réelles `DRAFT=sonnet LLM=haiku JUDGE=sonnet` sur deux documents réels, pour prouver qu'un générateur bon marché réussit sur le volume.","why":"Vérifier hors laboratoire que le split rend un modèle bon marché viable comme extracteur de claims.","result":"Le split résout bien le draft (sonnet passe le schéma), mais Haiku PARAPHRASE une partie des citations → le grounding verbatim rejette → `abandoned` (fail-safe : aucun pack, aucun dégât). Le goulot passe du « draft schéma-invalide » à la « fidélité verbatim des claims ». Prochains leviers : durcir la consigne verbatim, passer le contenu amont dans le contexte, golden-set d'évaluation.","packs":["grounding-anti-hallucination","eval-driven-development"]},{"title":"Grounding verbatim comme invariant dur","status":"validé","tested":"Exiger que chaque citation d'un claim existe LITTÉRALEMENT dans le snapshot de sa source, vérifié hors-ligne, quel que soit le tier de modèle.","why":"C'est le différenciateur du produit : un modèle, même bon marché, ne peut pas faire mentir un pack sur ses sources.","result":"Le gate tient quel que soit le modèle — c'est lui qui a fait échouer (à juste titre) Haiku sur les claims. La confiance ne dépend pas du tier choisi.","packs":["grounding-anti-hallucination","human-in-the-loop"]},{"title":"Zéro-dépendance, hexagonal, développement piloté par les tests","status":"validé","tested":"`.mjs` sans aucune dépendance runtime, tests `node:test`, architecture hexagonale (cœur pur sans I/O), et exécution en subagent-driven-development (un implémenteur + un relecteur par tâche, cycle TDD RED → GREEN).","why":"Le risque dominant identifié est l'over-engineering ; cette discipline garde le cœur testable et les changements petits et réversibles.","result":"Guards d'architecture verts, suite déterministe sans I/O, chaque comportement prouvé RED puis GREEN. Permet d'itérer vite sans casser les invariants.","packs":["right-sizing-yagni"]},{"title":"Mesurer ce que le grounding ne voit pas : cadre d'éval rubriqué","status":"en-cours","date":"2026-07-09","tested":"Après le constat que le groundingRate sature à 1.0 jusqu'en Haiku (il recopie même les fautes de la source), établir un cadre d'éval rubriqué réutilisable : une checklist décidable en cœur pur (grounding, couverture, redondance de surface, anti quote-mining structurel) + 7 dimensions jugées à ancres comportementales 0..3 (entailment, saillance, correction, couverture, incertitude, pédagogie, non-redondance), notées item par item avec preuve verbatim par un juge cross-family, agrégées en VECTEUR de scorecards (jamais un composite-gate), calibrées par dimension (weightedKappa contre un golden humain), comparées en pairwise (anti-position, held-out) avec attribution delta-vs-bruit par intervalle de confiance bootstrap.","why":"Le différenciateur du produit — le grounding verbatim — est un invariant-PLANCHER : une fois saturé, il ne discrimine plus la qualité. Optimiser les prompts sans instrument sur l'entailment réel, la saillance, la correction et la couverture, c'est régler à l'aveugle. Il fallait un cadre qui reste cohérent entre modèles ET entre versions de prompt, réutilisable étape par étape.","result":"Cadre conçu et posé : cœur pur (rubrique versionnée, agrégation vecteur, inférence seedée, weightedKappa, garde cross-family, specs par dimension), juge adapter (une seule famille câblée pour l'instant), harnais absolu + calibration (WARN, hors check) ; le harnais pairwise et un 2ᵉ juge cross-family sont conçus mais pas encore câblés. Principe directeur : tout ce qui est décidable reste en code (gratuit, déterministe), le juge est réservé au sémantique irréductible et n'est cru qu'au-dessus du seuil de calibration κ par dimension. Prochains leviers : ratifier le golden humain (10–20/famille), câbler un vrai 2ᵉ fournisseur de juge, faire tourner un sweep pairwise réel puis instruire le prompt claims sur les dimensions faibles.","packs":["eval-driven-development","grounding-anti-hallucination"]},{"title":"Le sourcing est le plafond : l'ancre verbatim le rend décidable","status":"validé","date":"2026-07-10","tested":"Sourcer puis évaluer 6 types de sujets distincts, puis durcir l'étape « proposition de sources » : le modèle classe le type du sujet, dresse une carte de facettes, et pour CHAQUE source colle une citation VERBATIM (l'ancre) prouvant la facette. Un « sourcing scorecard » décidable (cœur pur) fetch chaque page et vérifie que l'ancre existe LITTÉRALEMENT dans le texte LIVE, plus des checks de fraîcheur / diversité de domaines / redondance de surface.","why":"Le grounding verbatim ne vérifie qu'une chose — citation ⊂ snapshot — et il est saturé (même un modèle bon marché recopie exactement). Il ne voit PAS si la source est vivante, à-propos, à jour ou bien attribuée. Or une fiche ne peut jamais couvrir ni corriger ce que ses sources ne contiennent pas : le sourcing est le vrai plafond de qualité. Le défaut n°1 mesuré est la SUR-PROMESSE — le modèle annonce une citation qui n'est pas réellement sur la page.","result":"L'ancre verbatim déplace la frontière : « la source couvre-t-elle X ? » (jugé) devient « la phrase existe-t-elle sur la page live ? » (décidable, gratuit). Validé sur du réel : le scorecard attrape une vraie sur-promesse qu'un pipeline naïf aurait laissé casser le grounding en aval. Piège rencontré : vérifier l'ancre contre le HTML brut donne des faux négatifs — il faut stripper le HTML en texte, comme le pipeline snapshote. C'est le mouvement du grounding, appliqué au plafond.","packs":["grounding-anti-hallucination","eval-driven-development"]},{"title":"Gate de sourcing fail-closed : empêcher plutôt que gâcher (ADR 0011)","status":"validé","date":"2026-07-10","tested":"Brancher le sourcing scorecard comme gate BLOQUANT en tête de génération : une proposal dont une source est morte ou dont l'ancre est absente de la page live est ABANDONNÉE avant de dépenser un seul appel de génération. Le gate juge l'intersection proposal ∩ sources curées par l'humain, bloque sur la groundabilité (live + ancre) et laisse fraîcheur / redondance en simple avertissement. Rampe shadow → enforce.","why":"Mesurer ne suffit pas : tant que le verdict est indicatif, une proposal défaillante continue de gâcher des générations (pack abandonné en aval) ou pire, produit un claim « groundé mais creux » (citation vraie tirée d'une page hors-sujet). Il fallait passer de mesurer à EMPÊCHER, en amont.","result":"Le plafond de qualité devient enforced : validé end-to-end, une sur-promesse réelle déclenche l'abandon sans jamais appeler le générateur. Leçon de PROCESS marquante : la revue finale de branche a rattrapé un bug d'intégration que les revues par tâche avaient toutes manqué — le gate jugeait la proposal COMPLÈTE alors que la génération tourne sur les sources CURÉES par l'humain, si bien que décocher la source défaillante l'aurait quand même bloquée. Corrigé (juger l'intersection, bloquer sur la seule groundabilité). Preuve que la revue par tâche ne remplace pas une relecture des coutures de bout en bout.","packs":["guardrails","eval-driven-development","human-in-the-loop"]},{"title":"Calibrer le juge de sourcing avec un 2ᵉ juge cheap : ce que κ dit et ne dit pas","status":"validé","date":"2026-07-10","tested":"Brancher un 2ᵉ juge cross-family via OpenRouter (gpt-4o-mini, famille openai ≠ anthropic) et lancer une vraie calibration de stabilité inter-modèle : 10 proposals à qualité VARIÉE (conçues pour étaler les scores 0..3 par dimension), κ pondéré par dimension entre les deux familles, avec un verdict qui distingue honnêtement l'absence de variance (non-discriminant) d'une vraie reproductibilité (stable).","why":"La stabilité inter-modèle était la fiabilité restée gatée depuis le début, faute d'une 2ᵉ famille de juge. Question secondaire : un modèle CHEAP suffit-il comme 2ᵉ juge ? Sans ce run, le juge jugé restait « mesurable » sans être « mesuré ».","result":"La calibration DISCRIMINE : authority est reproductible inter-famille (κ=0.949), les dims sémantiques (coverage/pertinence/coi) ne le sont pas (κ 0.15–0.29), contrepoint reste incalibrable (abstentions + désaccord). Aucune dim n'est ressortie faussement « stable » par variance dégénérée — la garde non-discriminant a tenu. LEÇON n°1 : un 2ᵉ juge CHEAP conflate « rubrique sous-spécifiée » et « juge trop faible » ; durcir les ancres pour faire monter κ contre gpt-4o-mini serait du teaching-to-a-weak-judge (Goodhart). On ne touche donc PAS aux ancres tant qu'un juge plus fort (ou un golden humain) n'a pas attribué le désaccord. Indice : le même juge cheap s'accorde parfaitement sur authority (dim facile) → la difficulté est propre à chaque dimension, pas un bruit global.","packs":["eval-driven-development","calibration","anti-goodhart"]},{"title":"Attribuer un désaccord de juge : un 2ᵉ juge FORT sépare « rubrique faible » de « juge faible »","status":"validé","date":"2026-07-10","tested":"Relancer la MÊME calibration de sourcing avec un juge OpenRouter FORT (gpt-4o) au lieu du cheap (gpt-4o-mini) pour attribuer le désaccord ; instrumenter les abstentions par juge (helper pur pairWithAbstention) ; construire le harnais juge-vs-golden (exactitude) ; et tenter un durcissement d'ancre sur la dimension confirmée sous-spécifiée.","why":"Un désaccord inter-juge avec un modèle CHEAP ne dit pas si la RUBRIQUE est floue ou si le JUGE est trop faible. Toucher les ancres sans attribuer, c'est risquer d'optimiser du bruit (Goodhart / teaching-to-a-weak-judge).","result":"Attribution NETTE : coverage κ 0.15→0.69 rien qu'en passant à un juge fort → c'était le JUGE, PAS la rubrique (l'avoir durcie aurait optimisé du bruit ; on avait justement différé — validé a posteriori). pertinence reste ~0 même avec un juge fort → rubrique. MAIS 2e leçon, plus dure : le durcissement de pertinence tenté ensuite est NON concluant (Δκ +0.14 INDISTINGUABLE du bruit — les dims dont les ancres n'ont PAS bougé ont varié de 0.12 à 0.19 entre deux runs uniques) → reverté. Conclusion méthodo : (1) toujours attribuer avec un juge fort AVANT de durcir ; (2) un seul tirage ne permet PAS de mesurer l'effet d'un changement d'ancre — prérequis = N-tirages + intervalle de confiance au harnais. Bonus : l'instrumentation d'abstention montre que le n-insuffisant de contrepoint vient des abstentions (gpt-4o 6/10), pas d'un désaccord.","packs":["eval-driven-development","calibration","anti-goodhart"]}]},{"schemaVersion":"1.0","slug":"techwatch","title":"TechWatch IA","goal":"Construire une plateforme de veille technologique assistée par IA produisant des synthèses de migration fiables, sourcées et vérifiables.","summary":"Le différenciateur du projet est la confiance : chaque affirmation cite sa source. L'architecture est un workflow LLM déterministe, eval-driven, long-context d'abord (zéro RAG au MVP), avec relecture humaine. Ce projet rassemble les leçons d'ingénierie IA mobilisées, reliées aux packs de la bibliothèque. Le curriculum complet (20 sujets) est désormais disponible en packs groundés ci-dessous.","tags":["veille","llm","rag","eval","architecture"],"status":"actif","externalCurriculum":"techwatch/","path":[{"packSlug":"workflow-deterministe-vs-agents","why":"Le cœur : orchestrer 9 étapes plutôt que des agents autonomes."},{"packSlug":"long-context-rag-fine-tuning","why":"Pourquoi le MVP est long-context, pas RAG."},{"packSlug":"prompt-engineering-sorties-structurees","why":"Sorties structurées + citations à chaque appel LLM."},{"packSlug":"grounding-anti-hallucination","why":"Règles 1 & 2 : citations obligatoires, « null si absent »."},{"packSlug":"eval-driven-development","why":"Golden set + assertions déterministes = la porte qualité."},{"packSlug":"llm-as-judge","why":"Compléter l’éval hors chemin critique."},{"packSlug":"guardrails","why":"Garde-fous en couches avant publication."},{"packSlug":"human-in-the-loop","why":"Règle 3 : relecture humaine en gate."},{"packSlug":"securite-llm-owasp","why":"Le contenu collecté = donnée non fiable (prompt injection)."},{"packSlug":"finops-ia-couts","why":"Coût/synthèse maîtrisé : prompt caching, model routing."},{"packSlug":"observabilite-llm","why":"Mesurer coût & qualité dès le jour 1."},{"packSlug":"detection-de-version","why":"Le déclencheur : polling GitHub + ETags."},{"packSlug":"collecte-api-first-extraction","why":"Récupérer les sources officielles : API-first."},{"packSlug":"ssrf-allowlist-crawler","why":"Sécuriser le crawler : allowlist de domaines."},{"packSlug":"monolithe-modulaire-ddd","why":"Architecture : monolithe modulaire + workers."},{"packSlug":"serverless-event-driven","why":"Charge bursty → serverless scale-to-zero."},{"packSlug":"notifications-fan-out-idempotence","why":"Notifier les abonnés : fan-out idempotent."},{"packSlug":"choix-gestion-modeles","why":"Choisir/piloter les modèles (Haiku/Sonnet/Opus)."},{"packSlug":"provenance-versionnement-contenu","why":"Provenance + versionnement = audit trail."},{"packSlug":"right-sizing-yagni","why":"Le fil rouge : éviter l’over-engineering."}],"lessons":[{"title":"Règle 1 — Citations obligatoires","body":"Chaque affirmation d'une synthèse pointe sa source officielle (URL + section). Une affirmation non sourçable est retirée.","decision":"Grounding vérifié verbatim comme invariant.","packs":["grounding-anti-hallucination"]},{"title":"Règle 2 — « null si absent »","body":"Interdiction d'inventer une version, une API ou un breaking change : pas dans les sources → null, signalé.","decision":"Anti-hallucination par contrainte de sortie.","packs":["grounding-anti-hallucination","guardrails"]},{"title":"Règle 3 — Relecture humaine","body":"Aucune synthèse n'est diffusée sans validation humaine ; le bloc 2 la fait passer de 100 % à un échantillonnage ciblé.","decision":"Human-in-the-loop en gate de publication.","packs":["human-in-the-loop","eval-driven-development"]},{"title":"Workflow déterministe, pas d'agents","body":"Les 9 étapes du pipeline sont connues et ordonnées : on orchestre des étapes, on ne délègue pas à des agents autonomes.","decision":"Pipeline décomposé et évaluable.","packs":["workflow-deterministe-vs-agents"]},{"title":"Long-context d'abord","body":"Le corpus d'une transition de version tient dans la fenêtre : zéro base vectorielle au MVP.","decision":"RAG seulement si un besoin de recherche est prouvé.","packs":["long-context-rag-fine-tuning"]},{"title":"Éval = la nouvelle porte qualité","body":"Un golden set + des assertions déterministes bloquent la publication ; le LLM-judge complète hors chemin critique.","decision":"Eval-driven development.","packs":["eval-driven-development","llm-as-judge"]}]}];
